import { ethers } from 'ethers';

// Initialize ethers provider
const provider = new ethers.providers.Web3Provider(window.ethereum, 'any');
let signer;

// Connect to wallet
async function connectWallet() {
  await provider.send('eth_requestAccounts', []);
  signer = provider.getSigner();
}

// Validate user input
function validateInput(input) {
  const regex = /^[0-9a-fA-Fx]+$/;
  return regex.test(input);
}

// Interact with smart contract
async function interactWithContract(contractAddress, abi, functionName, params) {
  if (!validateInput(contractAddress)) {
    throw new Error('Invalid contract address');
  }

  const contract = new ethers.Contract(contractAddress, abi, signer);

  if (!contract[functionName]) {
    throw new Error('Invalid function name');
  }

  try {
    const tx = await contract[functionName](...params);
    console.log('Transaction sent:', tx.hash);
    await tx.wait();
    console.log('Transaction confirmed:', tx.hash);
  } catch (error) {
    console.error('Transaction failed:', error);
  }
}

// Example usage
async function executeTransaction() {
  const contractAddress = document.getElementById('contractAddress').value;
  const abi = JSON.parse(document.getElementById('abi').value);
  const functionName = document.getElementById('functionName').value;
  const params = JSON.parse(document.getElementById('params').value);

  if (!validateInput(contractAddress) || !Array.isArray(params)) {
    alert('Invalid input');
    return;
  }

  await connectWallet();
  await interactWithContract(contractAddress, abi, functionName, params);
}

// HTML elements for user input
document.getElementById('executeButton').addEventListener('click', executeTransaction);